import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import Nav from './Nev';

const MyOrders = () => {
  const [orders, setOrders] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const uid = localStorage.getItem("id", 0);
  const uname = localStorage.getItem("uname") || "Customer";
  const navigate = useNavigate();

  useEffect(() => {
    if (!localStorage.getItem("islogin")) {
      navigate('/login');
      return;
    }
    fetchOrders();
  }, []);

  const fetchOrders = async () => {
    try {
      const response = await axios.get('http://localhost/Petshop/showorder.php?uid=' + uid);
      setOrders(response.data);
      setIsLoading(false);
    } catch (error) {
      console.error('Error:', error);
      setIsLoading(false);
    }
  };

  const totalSpent = orders.reduce((sum, o) => sum + parseInt(o.amount || 0), 0);

  const styles = {
    page: {
      minHeight: '100vh',
      backgroundColor: '#f0f4f8',
      fontFamily: "'Segoe UI', sans-serif",
    },
    container: {
      maxWidth: '900px',
      margin: '30px auto',
      padding: '0 16px 60px',
    },
    topRow: {
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      marginBottom: '24px',
    },
    title: {
      fontSize: '26px',
      fontWeight: '700',
      color: '#1a202c',
      margin: 0,
    },
    shopBtn: {
      padding: '10px 20px',
      backgroundColor: '#38a169',
      color: 'white',
      border: 'none',
      borderRadius: '10px',
      cursor: 'pointer',
      fontWeight: '600',
      fontSize: '14px',
    },
    statsRow: {
      display: 'grid',
      gridTemplateColumns: '1fr 1fr 1fr',
      gap: '16px',
      marginBottom: '24px',
    },
    statCard: {
      backgroundColor: 'white',
      borderRadius: '14px',
      padding: '18px 20px',
      boxShadow: '0 4px 16px rgba(0,0,0,0.06)',
      textAlign: 'center',
    },
    statIcon: {
      fontSize: '28px',
      marginBottom: '6px',
    },
    statValue: {
      fontSize: '22px',
      fontWeight: '800',
      color: '#2d3748',
    },
    statLabel: {
      fontSize: '12px',
      color: '#a0aec0',
      marginTop: '2px',
    },
    card: {
      backgroundColor: 'white',
      borderRadius: '16px',
      boxShadow: '0 4px 20px rgba(0,0,0,0.07)',
      overflow: 'hidden',
    },
    tableHeader: {
      display: 'grid',
      gridTemplateColumns: '0.8fr 1.5fr 1fr 1fr 1.2fr',
      padding: '14px 24px',
      backgroundColor: '#f7fafc',
      borderBottom: '2px solid #e2e8f0',
      fontWeight: '700',
      color: '#4a5568',
      fontSize: '12px',
      textTransform: 'uppercase',
      letterSpacing: '0.06em',
    },
    tableRow: {
      display: 'grid',
      gridTemplateColumns: '0.8fr 1.5fr 1fr 1fr 1.2fr',
      padding: '16px 24px',
      borderBottom: '1px solid #edf2f7',
      alignItems: 'center',
    },
    orderNum: {
      fontWeight: '700',
      color: '#4299e1',
      fontSize: '14px',
    },
    orderId: {
      fontSize: '11px',
      color: '#a0aec0',
      fontFamily: 'monospace',
      wordBreak: 'break-all',
    },
    itemsBadge: {
      backgroundColor: '#ebf8ff',
      color: '#2b6cb0',
      padding: '4px 10px',
      borderRadius: '20px',
      fontSize: '13px',
      fontWeight: '600',
      display: 'inline-block',
    },
    date: {
      color: '#718096',
      fontSize: '13px',
    },
    amount: {
      fontWeight: '700',
      color: '#276749',
      fontSize: '15px',
    },
    statusBadge: {
      backgroundColor: '#f0fff4',
      color: '#276749',
      padding: '4px 10px',
      borderRadius: '20px',
      fontSize: '12px',
      fontWeight: '600',
      border: '1px solid #9ae6b4',
      display: 'inline-block',
    },
    emptyBox: {
      textAlign: 'center',
      padding: '60px 20px',
      color: '#718096',
    },
    emptyIcon: {
      fontSize: '60px',
      marginBottom: '12px',
    },
    loadingBox: {
      textAlign: 'center',
      padding: '60px',
      color: '#718096',
      fontSize: '18px',
    }
  };

  return (
    <div style={styles.page}>
      <Nav />
      <div style={styles.container}>

        {/* Header */}
        <div style={styles.topRow}>
          <h1 style={styles.title}>📦 My Orders</h1>
          <button style={styles.shopBtn} onClick={() => navigate('/product')}>
            + Naya Order
          </button>
        </div>

        {/* Stats Cards */}
        {!isLoading && (
          <div style={styles.statsRow}>
            <div style={styles.statCard}>
              <div style={styles.statIcon}>🛒</div>
              <div style={styles.statValue}>{orders.length}</div>
              <div style={styles.statLabel}>Total Orders</div>
            </div>
            <div style={styles.statCard}>
              <div style={styles.statIcon}>💰</div>
              <div style={styles.statValue}>₹{totalSpent.toLocaleString()}</div>
              <div style={styles.statLabel}>Total Spent</div>
            </div>
            <div style={styles.statCard}>
              <div style={styles.statIcon}>✅</div>
              <div style={styles.statValue}>{orders.length}</div>
              <div style={styles.statLabel}>Completed</div>
            </div>
          </div>
        )}

        {/* Orders Table */}
        <div style={styles.card}>
          {isLoading ? (
            <div style={styles.loadingBox}>⏳ Orders load ho rahe hain...</div>
          ) : orders.length === 0 ? (
            <div style={styles.emptyBox}>
              <div style={styles.emptyIcon}>📭</div>
              <h3 style={{ color: '#2d3748', marginBottom: '8px' }}>Koi order nahi hai abhi tak</h3>
              <p>Pehla order karo aur yahan dikhega!</p>
              <button
                onClick={() => navigate('/product')}
                style={{ ...styles.shopBtn, marginTop: '16px', padding: '12px 32px' }}
              >
                Products Dekhein
              </button>
            </div>
          ) : (
            <>
              <div style={styles.tableHeader}>
                <span>#</span>
                <span>Order ID</span>
                <span>Items</span>
                <span>Amount</span>
                <span>Status</span>
              </div>
              {orders.map((order, index) => (
                <div key={order.oid} style={styles.tableRow}>
                  <div style={styles.orderNum}>#{index + 1}</div>
                  <div style={styles.orderId}>{order.order_id || order.oid}</div>
                  <div>
                    <span style={styles.itemsBadge}>{order.totalitem} items</span>
                  </div>
                  <div style={styles.amount}>₹{parseInt(order.amount).toLocaleString()}</div>
                  <div>
                    <span style={styles.statusBadge}>✓ Delivered</span>
                  </div>
                </div>
              ))}
            </>
          )}
        </div>

        <button
          onClick={() => navigate('/')}
          style={{
            marginTop: '16px',
            background: 'none',
            border: 'none',
            color: '#718096',
            cursor: 'pointer',
            fontSize: '14px',
            textDecoration: 'underline',
            display: 'block',
            textAlign: 'center',
            width: '100%',
          }}
        >
          ← Home pe jaayein
        </button>
      </div>
    </div>
  );
};

export default MyOrders;
